CREATE TABLE IF NOT EXISTS promotion_offer (
    id BIGINT NOT NULL,
    uuid VARCHAR(64) NOT NULL,
    tenant_id BIGINT NOT NULL,
    organization_id BIGINT NOT NULL DEFAULT 0,
    offer_no VARCHAR(128) NOT NULL,
    offer_code VARCHAR(128),
    offer_type VARCHAR(32) NOT NULL,
    audience_scope VARCHAR(32) NOT NULL DEFAULT 'ALL',
    combinability VARCHAR(32) NOT NULL DEFAULT 'EXCLUSIVE',
    priority INTEGER NOT NULL DEFAULT 0,
    goods_scope VARCHAR(32) NOT NULL DEFAULT 'BOTH',
    current_offer_version_id BIGINT,
    display_name VARCHAR(256) NOT NULL,
    description VARCHAR(1024),
    starts_at TIMESTAMPTZ NOT NULL,
    ends_at TIMESTAMPTZ,
    status INTEGER NOT NULL DEFAULT 1,
    version BIGINT NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL,
    updated_at TIMESTAMPTZ NOT NULL,
    CONSTRAINT pk_promotion_offer PRIMARY KEY (id),
    CONSTRAINT uk_promotion_offer_uuid UNIQUE (uuid),
    CONSTRAINT uk_promotion_offer_no UNIQUE (tenant_id, offer_no),
    CONSTRAINT chk_promotion_offer_dates CHECK (ends_at IS NULL OR ends_at >= starts_at)
);

CREATE INDEX IF NOT EXISTS idx_promotion_offer_tenant_status
    ON promotion_offer (tenant_id, organization_id, status, priority DESC, starts_at DESC);
CREATE INDEX IF NOT EXISTS idx_promotion_offer_tenant_type
    ON promotion_offer (tenant_id, offer_type, status);

CREATE TABLE IF NOT EXISTS promotion_offer_version (
    id BIGINT NOT NULL,
    uuid VARCHAR(64) NOT NULL,
    tenant_id BIGINT NOT NULL,
    offer_id BIGINT NOT NULL,
    version_no INTEGER NOT NULL,
    discount_type VARCHAR(32) NOT NULL,
    discount_value NUMERIC(18, 2) NOT NULL DEFAULT 0,
    minimum_amount NUMERIC(18, 2) NOT NULL DEFAULT 0,
    maximum_discount_amount NUMERIC(18, 2),
    maximum_quantity_per_order INTEGER NOT NULL DEFAULT 1,
    currency_code VARCHAR(10) NOT NULL DEFAULT '',
    rule_json JSONB,
    stack_rule_json JSONB,
    created_at TIMESTAMPTZ NOT NULL,
    CONSTRAINT pk_promotion_offer_version PRIMARY KEY (id),
    CONSTRAINT uk_promotion_offer_version_uuid UNIQUE (uuid),
    CONSTRAINT uk_promotion_offer_version_unique UNIQUE (tenant_id, offer_id, version_no),
    CONSTRAINT chk_promotion_offer_version_discount_non_negative CHECK (discount_value >= 0 AND minimum_amount >= 0)
);

CREATE INDEX IF NOT EXISTS idx_promotion_offer_version_offer
    ON promotion_offer_version (tenant_id, offer_id, version_no DESC);

CREATE TABLE IF NOT EXISTS promotion_coupon_stock (
    id BIGINT NOT NULL,
    uuid VARCHAR(64) NOT NULL,
    tenant_id BIGINT NOT NULL,
    organization_id BIGINT NOT NULL DEFAULT 0,
    offer_id BIGINT NOT NULL,
    offer_version_id BIGINT NOT NULL,
    stock_no VARCHAR(128) NOT NULL,
    stock_type VARCHAR(32) NOT NULL,
    total_quantity BIGINT NOT NULL DEFAULT 0,
    available_quantity BIGINT NOT NULL DEFAULT 0,
    claimed_quantity BIGINT NOT NULL DEFAULT 0,
    redeemed_quantity BIGINT NOT NULL DEFAULT 0,
    locked_quantity BIGINT NOT NULL DEFAULT 0,
    per_user_limit INTEGER NOT NULL DEFAULT 1,
    claim_starts_at TIMESTAMPTZ,
    claim_ends_at TIMESTAMPTZ,
    status INTEGER NOT NULL DEFAULT 1,
    version BIGINT NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL,
    updated_at TIMESTAMPTZ NOT NULL,
    CONSTRAINT pk_promotion_coupon_stock PRIMARY KEY (id),
    CONSTRAINT uk_promotion_coupon_stock_uuid UNIQUE (uuid),
    CONSTRAINT uk_promotion_coupon_stock_no UNIQUE (tenant_id, stock_no),
    CONSTRAINT chk_promotion_coupon_stock_quantities_non_negative CHECK (
        total_quantity >= 0 AND available_quantity >= 0 AND claimed_quantity >= 0
        AND redeemed_quantity >= 0 AND locked_quantity >= 0
    ),
    CONSTRAINT chk_promotion_coupon_stock_available_le_total CHECK (
        stock_type = 'UNLIMITED' OR (available_quantity + claimed_quantity <= total_quantity)
    )
);

CREATE INDEX IF NOT EXISTS idx_promotion_coupon_stock_offer
    ON promotion_coupon_stock (tenant_id, offer_id, status);

