    code_no VARCHAR(128) NOT NULL,
    promotion_code VARCHAR(128) NOT NULL,
    code_type VARCHAR(32) NOT NULL,
    max_claims INTEGER NOT NULL DEFAULT 1,
    claimed_quantity INTEGER NOT NULL DEFAULT 0,
    starts_at TIMESTAMPTZ,
    expires_at TIMESTAMPTZ,
    status INTEGER NOT NULL DEFAULT 1,
    version BIGINT NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL,
    updated_at TIMESTAMPTZ NOT NULL,
    CONSTRAINT pk_promotion_code PRIMARY KEY (id),
    CONSTRAINT uk_promotion_code_uuid UNIQUE (uuid),
    CONSTRAINT uk_promotion_code_no UNIQUE (tenant_id, code_no),
    CONSTRAINT uk_promotion_code_value UNIQUE (tenant_id, promotion_code),
    CONSTRAINT chk_promotion_code_claimed_le_max CHECK (claimed_quantity <= max_claims)
);

CREATE INDEX IF NOT EXISTS idx_promotion_code_stock
    ON promotion_code (tenant_id, stock_id, status);

